-- Seed updates that are safe to re-run on every deployment.
-- Keeps user_attraction_status for existing attractions, and deletes statuses only for removed attractions (via ON DELETE CASCADE).

CREATE UNIQUE INDEX IF NOT EXISTS ux_attractions_name_city
    ON attractions (name, city);

INSERT INTO attraction_categories (name, icon_url, color)
VALUES
    ('Музей', NULL, '#1E88E5'),
    ('Храм', NULL, '#F97316'),
    ('Памятник', NULL, '#EAB308'),
    ('Достопримечательность', NULL, '#8E24AA'),
    ('Парк', NULL, '#43A047')
ON CONFLICT (name) DO NOTHING;

BEGIN;

WITH seed(name, short_description, full_description, category_name, latitude, longitude, address, city) AS (
    VALUES
        ('Бизнес-центр «Высоцкий» со смотровой площадкой', 'Одно из самых стильных зданий Екатеринбурга', 'Одно из самых стильных зданий Екатеринбурга как магнит притягивает всех, кто хочет полюбоваться городской застройкой с высоты. С открытой смотровой площадки на 52 этаже небоскреба на высоте 186 м открывается фантастическая панорама на улицы и культовые места уральской столицы. В ясную погоду хорошо видны достопримечательности на расстоянии 25 км: от стоящего рядом оперного театра до скал-останцев возле озера Шарташ.', 'Достопримечательность', 56.836121, 60.614237, 'Екатеринбург, Малышева, 51', 'Екатеринбург'),
        ('Парк Маяковского', 'Центральный парк культуры и отдыха имени Маяковского — любимое место для семейного отдыха в Екатеринбурге. ', 'Он занимает около 100 га, которые разделены на территории для тихого отдыха, пешеходных и велопрогулок по лесу, занятий спортом, развлечений и пикников. ', 'Парк', 56.812217, 60.646765, 'Екатеринбург, Мичурина, 230', 'Екатеринбург'),
        ('Исторический сквер (Плотинка)', 'Место основания Екатеринбурга и главная набережная города.', 'Исторический сквер на берегу Городского пруда — это колыбель Екатеринбурга, заложенная в 1723 году. Здесь сохранились остатки первой заводской плотины, здания заводоуправления и проводятся масштабные городские праздники. Идеальное место для знакомства с истоками уральской столицы.', 'Достопримечательность', 56.8400, 60.6010, 'Екатеринбург, пр. Ленина, 24А', 'Екатеринбург'),
        ('Памятник основателям Екатеринбурга', 'Бронзовый монумент Татищеву и де Геннину на берегу пруда.', 'Установленный к 275-летию города, памятник изображает двух основателей Екатеринбурга на гранитном постаменте с барельефами. Место стало символом города и площадкой для официальных церемоний.', 'Памятник', 56.838158, 60.605889, 'Екатеринбург, Исторический сквер', 'Екатеринбург'),
        ('Музей истории Екатеринбурга', 'Современный музей с интерактивными экспозициями о прошлом города.', 'Расположен в здании бывшего Главного почтамта, музей предлагает мультимедийные инсталляции и уникальные артефакты. Посетители погружаются в атмосферу дореволюционного Екатеринбурга и следят за индустриальным развитием Урала.', 'Музей', 56.84064, 60.61144, 'Екатеринбург, ул. Карла Либкнехта, 26', 'Екатеринбург'),
        ('Большой Златоуст', 'Величественная восстановленная колокольня — архитектурный символ города.', 'Изначально построенная в XIX веке и разрушенная в 1930-х, колокольня высотой 76 м была воссоздана в 2010-х. Внутри расположен музей уральской православной архитектуры, а с обзорной площадки открывается панорама центра.', 'Храм', 56.83466, 60.6004, 'Екатеринбург, ул. 8 Марта, 8А', 'Екатеринбург'),
        ('Усадьба Расторгуевых-Харитоновых', 'Шедевр классицизма, окруженный мистическими легендами.', 'Построенная в конце XVIII века для купца Расторгуева, усадьба славится роскошными интерьерами и зимним садом. Сегодня это филиал краеведческого музея, где проходят выставки и концерты классической музыки.', 'Достопримечательность', 56.845613, 60.611126, 'Екатеринбург, ул. Карла Либкнехта, 44', 'Екатеринбург'),
        ('Харитоновский сад', 'Живописный парк в английском стиле у знаменитой усадьбы.', 'Разбитый в начале XIX века, сад сохранил оригинальную планировку с каскадными прудами и редкими деревьями. После реставрации стал идеальным местом для тихих прогулок в историческом центре.', 'Парк', 56.84577, 60.61368, 'Екатеринбург, ул. Карла Либкнехта, 44А', 'Екатеринбург'),
        ('Памятник клавиатуре', 'Бетонная скульптура в виде компьютерной клавиатуры на набережной.', 'Установленный в 2005 году арт-объект состоит из 104 клавиш высотой до 120 см. Символизирует связь города с IT-сферой и является популярной фотозоной для молодежи и туристов.', 'Памятник', 56.832392, 60.607548, 'Екатеринбург, набережная Рабочей Молодёжи', 'Екатеринбург'),
        ('Музей изобразительных искусств', 'Крупнейшая художественная коллекция Урала.', 'Фонды насчитывают более 25 тысяч экспонатов: от древнерусских икон и западноевропейской живописи до авангарда Малевича. Регулярно проводятся выставки международного уровня и образовательные программы.', 'Музей', 56.835213, 60.603380, 'Екатеринбург, ул. Воеводина, 5', 'Екатеринбург'),
        ('Шарташские каменные палатки', 'Природный памятник из гранитных скал с древними рисунками.', 'Скалы возрастом более 300 млн лет возвышаются над лесом у озера Шарташ. Место обнаружения неолитических стоянок и наскальной живописи. Популярно среди туристов, геологов и любителей активного отдыха.', 'Достопримечательность', 56.845020, 60.684261, 'Екатеринбург, ул. 40 лет ВЛКСМ, Шарташ', 'Екатеринбург'),
        ('Ганина Яма', 'Монастырский комплекс на месте расстрела царской семьи.', 'Включает шесть деревянных храмов, освященных в честь каждого из убиенных членов императорской семьи. Место паломничества миллионов верующих, окруженное источниками и ухоженными лесными тропами.', 'Храм', 56.9419781, 60.4737654, 'Екатеринбург, ул. Братская, 108', 'Екатеринбург'),
        ('Парк Чкалова', 'Крупный зеленый массив с сосновыми борами и велодорожками.', 'Парк известен своими природными ландшафтами и спортивной инфраструктурой. Здесь проводятся городские марафоны и фестивали. Уютные аллеи и пруды создают атмосферу загородного отдыха.', 'Парк', 56.800603615306116, 60.56265213889747, 'Екатеринбург, ул. Чкалова', 'Екатеринбург'),
        ('Свердловский областной краеведческий музей', 'Главный музей области с коллекциями по природе и истории Урала.', 'Экспозиции охватывают миллионы лет: от палеонтологических находок и минералов до этнографии народов Урала. Предлагает интерактивные программы для детей и регулярные временные выставки.', 'Музей', 56.840975, 60.622337, 'Екатеринбург, ул. Ленина, 69', 'Екатеринбург'),
        ('Памятник В.С. Высоцкому и М. Влади', 'Бронзовая скульптура великого барда и его музы.', 'Установленный в 2006 году, памятник точно передает динамику встречи пары. Стал символом культурной жизни города и местом, где часто звучат песни барда.', 'Памятник', 56.837102, 60.615772, 'Екатеринбург, Красноармейская улица, 10', 'Екатеринбург'),
        ('Троицкий собор', 'Старейший каменный храм Екатеринбурга в стиле сибирского барокко.', 'Построенный в 1818–1827 годах, собор пережил революции, сохранив уникальные фрески и иконостас. Сегодня это действующий храм с богатой историей, привлекающий ценителей архитектуры.', 'Храм', 56.827222, 60.614167, 'Екатеринбург, ул. 8 Марта, 8', 'Екатеринбург'),
        ('Музей радио им. А.С. Попова', 'Уникальная экспозиция, посвященная изобретению радио.', 'Расположен в здании, где Попов демонстрировал первый приемник. Включает исторические аппараты, документы и интерактивные стенды о развитии связи от искрового передатчика до спутников.', 'Музей', 56.833476, 60.613006, 'Екатеринбург, ул. Розы Люксембург, 9', 'Екатеринбург'),
        ('Парк «Зеленая роща»', 'Уютный лесной парк с прудами и зонами для активного отдыха.', 'Парк сохранил естественный ландшафт, дополненный современными дорожками и спортивными объектами. Здесь проходят йога-сессии, выставки под открытым небом и сезонные фестивали.', 'Парк', 56.823778, 60.595790, 'Екатеринбург, улица Народной Воли', 'Екатеринбург'),
        ('Памятник Борису Ельцину', 'Стилизованный монумент первому президенту России.', 'Установленный в 2011 году памятник выполнен из белого мрамора в форме арки с изображением флага. Стал неотъемлемой частью современного городского ландшафта и точкой притяжения туристов.', 'Памятник', 56.84415, 60.5917, 'Екатеринбург, ул. Б. Ельцина, 3', 'Екатеринбург'),
        ('Дом Севастьянова', 'Яркий образец неоготики с мавританскими элементами.', 'Построенный в середине XIX века, дом поражает фантазийным декором: башенками, арками и восточными орнаментами. После реставрации фасады остаются открытыми для осмотра и фотосъемки.', 'Достопримечательность', 56.838889, 60.606389, 'Екатеринбург, ул. 8 Марта, 12', 'Екатеринбург'),
        ('Храм в честь Преображения Господня', 'Восстановленный кафедральный собор — центр духовной жизни.', 'Заложенный в XIX веке и воссозданный в 2000-х, собор символизирует возрождение православных традиций на Урале. Внутри хранятся почитаемые иконы и проводятся регулярные богослужения.', 'Храм', 56.780867, 60.649336, 'Екатеринбург, Походная улица, 2', 'Екатеринбург'),
        ('Музей «Дом Метенкова»', 'Фотографический музей в старинном купеческом доме.', 'Посвящен творчеству В. Метенкова, включает камеры XIX–XX веков и редкие снимки дореволюционного города. Регулярно проводит мастер-классы и выставки современной фотографии.', 'Музей', 56.842214, 60.613941, 'Екатеринбург, ул. Тургенева, 15', 'Екатеринбург'),
        ('Парк Лесоводов России', 'Тихий парк с экотропами и памятниками лесной промышленности.', 'Посвящен труду лесоводов и охране природы Урала. Проложены экологические маршруты, установлены стенды о флоре и фауне, находится мемориал «Лесоводам России».', 'Парк', 56.80564, 60.67629, 'Екатеринбург, ул. 8 Марта, 149', 'Екатеринбург'),
        ('Памятник А.С. Пушкину', 'Бронзовая фигура поэта в Литературном квартале.', 'Установленный в 1999 году, памятник изображает Пушкина в момент вдохновения. Расположен в центре главной прогулочной артерии, став популярной фотозоной и местом литературных вечеров.', 'Памятник', 56.842058, 60.607200, 'Екатеринбург, Пролетарская улица', 'Екатеринбург'),
        ('Музей камня и ювелирного искусства', 'Уникальная коллекция уральских самоцветов и ограненных минералов.', 'Демонстрирует богатство недр Урала: от малахита и родонита до изумрудов. Посетители видят исторические инструменты камнерезов и современные ювелирные шедевры.', 'Музей', 56.839187, 60.606910, 'Екатеринбург, пр. Ленина, 37', 'Екатеринбург'),
        ('Храм Великомученицы Екатерины', 'Действующий храм в честь небесной покровительницы города.', 'Построенный в 1770-х годах, храм сохранил дух старинной уральской архитектуры. Центр приходской жизни с воскресной школой и благотворительными программами.', 'Храм', 56.838359, 60.607458, 'Екатеринбург, ул. 8 Марта, 14', 'Екатеринбург'),
        ('Музей Свердловской железной дороги', 'Историко-технический музей о развитии транспорта на Урале.', 'Включает макеты паровозов, документы и форму железнодорожников. Освещает роль дороги в освоении Урала и индустриализации, привлекая специалистов и любителей истории.', 'Музей', 56.858742, 60.600728, 'Екатеринбург, ул. Вокзальная, 14', 'Екатеринбург'),
        ('Памятник «Черный тюльпан»', 'Мемориал воинам-интернационалистам, погибшим в Афганистане.', 'Установленный в 1991 году, представляет собой бронзовую композицию с самолетом и фигурами солдат. Место тихой памяти и скорби, куда ежегодно приходят ветераны и родные.', 'Памятник', 56.84315, 60.61734, 'Екатеринбург, ул. Куйбышева, 35', 'Екатеринбург'),
        ('Храм на Крови', 'На Вознесенской горке возвышается церковь, которая посвящена трагической странице в истории Екатеринбурга.', 'Вместительный храм высотой 60 м был построен в начале XXI века на месте дома инженера Ипатьева, в подвале которого в 1918 году расстреляли семью последнего российского императора. Ежегодно в ночь на 17 июля возле церкви собираются тысячи прихожан и идут крестным ходом из центра Екатеринбурга до Ганиной Ямы.', 'Храм', 56.8441, 60.6089, 'Екатеринбург, Царская, 10', 'Екатеринбург'),
        ('Музей-завод истории металлургии', 'Уникальный музей под открытым небом в Нижнем Тагиле', 'Расположен на территории старейшего металлургического завода Урала. Посетители видят действующие механизмы XIX века, доменные печи и знакомятся с историей уральской металлургии. Включает цеха, где ковали металл для танков Т-34.', 'Музей', 57.90532, 59.94438, 'Нижний Тагил, ул. Заводская, 1', 'Нижний Тагил'),
        ('Парк имени Бондина', 'Старейший парк Нижнего Тагила на берегу пруда', 'Разбит в середине XIX века, назван в честь управляющего тагильскими заводами. Сохранил вековые липы и сосны, пруды с лебедями, беседки. Популярное место для прогулок с панорамой на завод-музей.', 'Парк', 57.90500, 59.96000, 'Нижний Тагил, пр. Ленина, 2', 'Нижний Тагил'),
        ('Памятник танку Т-34', 'Легендарный танк на постаменте в Нижнем Тагиле', 'Установлен в честь тагильских танкостроителей, производивших Т-34 в годы Великой Отечественной войны. Символ трудового подвига города, ставшего одним из центров танковой промышленности СССР.', 'Памятник', 57.905887, 59.952332, 'Нижний Тагил, пр. Ленина', 'Нижний Тагил'),
        ('Скалы Каменный Пояс', 'Живописные скальные останцы на реке Исеть', 'Гранитные скалы высотой до 30 метров протянулись вдоль реки в Каменске-Уральском. Место притяжения альпинистов и туристов. С вершин открывается вид на город и окрестные леса.', 'Достопримечательность', 56.4100, 61.9200, 'Каменск-Уральский, ул. Скальная', 'Каменск-Уральский'),
        ('Часовня Александра Невского', 'Величественный собор в неорусском стиле', 'Построен в начале XX века в Каменске-Уральском. Отличается богатой кирпичной кладкой и золотыми куполами. Действующий храм с воскресной школой и хором.', 'Храм', 56.414115, 61.917796, 'Каменск-Уральский, просп. Победы, 1Б', 'Каменск-Уральский'),
        ('Свято-Николаевский мужской монастырь', 'Древнейшая обитель Урала в Верхотурье', 'Основан в 1604 году, один из старейших монастырей за Уралом. Сохранил каменные стены XVII века, соборы с фресками и мощи святых. Центр паломничества и духовного туризма.', 'Храм', 58.863378, 60.810727, 'Верхотурье, ул. Советская, 2', 'Верхотурье'),
        ('Ирбитский музей мотоциклов', 'Крупнейшая в России коллекция отечественных мотоциклов', 'Расположен в Ирбите — родине мотоцикла «Урал». Экспозиция включает редкие модели с 1940-х годов до современности, документы заводской истории и гоночные мотоциклы.', 'Музей', 57.66335, 63.08906, 'Ирбит, ул. Кирова, 53', 'Ирбит'),
        ('Невьянская наклонная башня', 'Уральская Пизанская башня XVIII века', 'Построена в 1720-х годах для Демидовых. Отклонение от вертикали составляет почти 2 метра. Внутри — акустический зал с уникальной слышимостью и старинные механизмы.', 'Достопримечательность', 57.48993, 60.22328, 'Невьянск, пл. Революции, 1', 'Невьянск'),
        ('Спасо-Преображенский собор', 'Барочный храм с «поющими» колоколами', 'Построен в Невьянске в 1750-х годах. Знаменит резным иконостасом и колокольней с музыкальным механизмом. Один из красивейших храмов Среднего Урала.', 'Храм', 57.48972, 60.22183, 'Невьянск, сквер Демидова, 1', 'Невьянск'),
        ('Гумешевский медный рудник', 'Легендарный рудник из сказов Бажова', 'Действовал в Полевском с XVIII века, дал название знаменитой Медной горе. Сейчас здесь музей под открытым небом с шахтами и штольнями. Место рождения мифов о Хозяйке Медной горы.', 'Достопримечательность', 56.46556, 60.19167, 'Полевской, ул. Гумешки', 'Полевской'),
        ('Свято-Пантейлемоновский женский монастырь', 'Женская обитель в Краснотурьинске', 'Основан в XIX веке при Богословском медеплавильном заводе. Сохранил каменный собор с фресками и старинные кельи. Место тихой молитвы и паломничества.', 'Храм', 59.773850, 60.221727, 'Краснотурьинск, Школьная улица, 15', 'Краснотурьинск'),
        ('Старо-Уткинский завод', 'Памятник промышленной архитектуры XVIII века', 'Расположен в Первоуральске. Сохранил плотину, здания цехов и плотину с водосбросом. Символ начала уральской металлургии и освоения края.', 'Достопримечательность', 57.18333, 59.26917, 'Первоуральск, ул. Заводская, 5', 'Первоуральск'),
        ('Парк Победы', 'Мемориальный комплекс в Ревде', 'Посвящен героям Великой Отечественной войны. Включает Вечный огонь, стелы с именами павших и аллею памяти. Место проведения памятных мероприятий.', 'Парк', 56.901956, 60.567641, 'Ревда, ул. Ленина, 45', 'Ревда'),
        ('Гора Качканар', 'Священная гора с буддийским монастырем', 'Гранитная гора высотой 878 м в одноименном городе. На вершине расположен буддийский монастырь Шад Тчуп Линг. Место силы и паломничества с панорамными видами.', 'Достопримечательность', 58.77010, 59.38300, 'Качканар, гора Качканар', 'Качканар'),
        ('Бажовские места', 'Литературный парк в Сысерти', 'Посвящен писателю Павлу Бажову, родившемуся в Сысерти. Включает скульптуры героев его сказов, беседки, пруды. Место проведения литературных праздников.', 'Парк', 56.5081, 60.7363, 'Сысерть, Природный парк Бажовские места', 'Сысерть'),
        ('Музей военной техники УГМК', 'Крупнейшая экспозиция бронетехники в России', 'Расположен в Верхней Пышме. Включает сотни единиц техники от Первой мировой до современности: танки, самолеты, артиллерию. Многие экспонаты на ходу.', 'Музей', 56.959724, 60.585830, 'Верхняя Пышма, ул. Заводская, 1', 'Верхняя Пышма'),
        ('Гора Благодать', 'Легендарная гора-останец в Кушве', 'Высота 384 м, одна из высших точек Среднего Урала. С вершины открывается вид на сотни километров. Место добычи магнитного железняка с XVIII века.', 'Достопримечательность', 58.288608, 59.787723, 'Кушва, гора Благодать', 'Кушва')
),
upserted AS (
    INSERT INTO attractions (name, short_description, full_description, category_id, latitude, longitude, address, city, image_urls)
    SELECT
        s.name,
        s.short_description,
        s.full_description,
        c.id,
        s.latitude,
        s.longitude,
        s.address,
        s.city,
        ARRAY[]::TEXT[]
    FROM seed s
    JOIN attraction_categories c ON c.name = s.category_name
    ON CONFLICT (name, city) DO UPDATE
    SET
        short_description = EXCLUDED.short_description,
        full_description  = EXCLUDED.full_description,
        category_id       = EXCLUDED.category_id,
        latitude          = EXCLUDED.latitude,
        longitude         = EXCLUDED.longitude,
        address           = EXCLUDED.address,
        image_urls        = EXCLUDED.image_urls
    RETURNING id, name, city
)
DELETE FROM attractions a
WHERE NOT EXISTS (
    SELECT 1
    FROM seed s
    WHERE s.name = a.name
      AND s.city = a.city
);

COMMIT;

